/**
 * Mock data for the Data › Carts & Abandonment record-explorer page.
 *
 * Ported from /Users/mac/Downloads/MAGELLAN UX/Data/magellan-data-carts.html
 * Currency converted ฿ → $ (same digits, $ symbol) per Magellan currency rule.
 *
 * A cart is the pre-order moment: contents, value, and what happened next.
 * Abandoned-cart value is POTENTIAL, never booked. The original template built
 * 50 deterministic records with a seeded RNG (mulberry32, seed 73); we reproduce
 * that generator verbatim so the rows are stable across renders, then expose the
 * frozen array (sorted newest-first) plus the typed column / filter metadata.
 */

/* ─────────────────────────── Types ─────────────────────────── */

export type CartStatus = "converted" | "recovered" | "abandoned";
export type Device = "Mobile" | "Desktop";

export interface CartItem {
  name: string;
  qty: number;
  amt: number;
}

export interface RecoveryEmail {
  sent: boolean;
  opened?: boolean;
  clicked?: boolean;
}

export interface CartRecord {
  id: string;
  /** ISO date (YYYY-MM-DD) — used for sorting & range filtering */
  date: string;
  /** ms epoch of the cart-start moment, for stable date sort */
  ts: number;
  time: string;
  customer: string;
  items: CartItem[];
  nItems: number;
  value: number;
  status: CartStatus;
  timeMin: number;
  timeLabel: string;
  exitStep: string;
  email: RecoveryEmail;
  source: string;
  device: Device;
  orderId: string | null;
  /** timeline steps: [label, timestamp] */
  tl: Array<[string, string]>;
}

export type ColumnKey =
  | "id"
  | "customer"
  | "status"
  | "value"
  | "exitStep"
  | "email"
  | "timeMin"
  | "device"
  | "source";

export interface ColumnDef {
  k: ColumnKey;
  label: string;
  on: boolean;
  num?: boolean;
  fixed?: boolean;
}

export type FilterKey = "status" | "exitStep" | "device";

/* ─────────────────────────── Seeded RNG (mulberry32, seed 73) ─────────────────────────── */

function mulberry32(a: number) {
  return function () {
    a |= 0;
    a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}
const rng = mulberry32(73);
const pick = <T>(arr: T[]): T => arr[Math.floor(rng() * arr.length)];
const between = (a: number, b: number) => a + Math.floor(rng() * (b - a + 1));

const FIRST = [
  "Somchai", "Nattaya", "Preecha", "Siriporn", "Wirote", "Apinya", "Thanawat",
  "Kanya", "Chaiwat", "Ratana", "Niran", "Sukanya", "Prasert", "Malee", "Anan",
  "Ploy", "Korn", "Benjamas", "Wichai", "Suda", "Decha", "Pim", "Krit", "Wanida",
  "Surasak", "Nicha", "Phong", "Araya", "Tawan", "Mali",
];
const LAST = [
  "Rakthong", "Sripongpun", "Charoensuk", "Thongsuk", "Janphen", "Mongkol",
  "Boonmee", "Phetcharat", "Saetang", "Wongphan", "Intara", "Chaiyo", "Pimchan",
  "Sutthi", "Krairit", "Hoeft", "Veerasak", "Anong", "Damrong", "Klahan",
];

// [name, unit price] — prices are the same digits as the template, now USD ($)
const CPRODUCTS: Array<[string, number]> = [
  ["Signature Rose Box · Large", 2890],
  ["Grand Anniversary Arrangement", 6900],
  ["Devil’s Chocolate Cake · Large", 2990],
  ["Swedish Princess Cake · Medium", 2190],
  ["Luxe Orchid Display", 4490],
  ["Hydrangea Arrangement", 2390],
  ["Banana Tiramisu · Large", 2290],
  ["Premium Gift Basket", 2490],
  ["Carnation Posy", 1812],
  ["Orange Hazelnut Dacquoise · Medium", 2490],
  ["Belgian Truffle Set · 12pc", 1190],
  ["Seasonal Tulip Bouquet", 2026],
];

const SOURCES = ["organic", "google_ads", "meta_ads", "direct", "email", "line_oa"];
// where the customer dropped off — the friction signal (neutral classification)
const EXIT_STEPS = ["Cart view", "Delivery date", "Address entry", "Payment", "Shipping options"];

function genCart(i: number): CartRecord {
  // status mix: converted (became an order), recovered (came back), abandoned (still gone)
  const r = rng();
  let status: CartStatus;
  if (r < 0.34) status = "converted";
  else if (r < 0.48) status = "recovered";
  else status = "abandoned";

  // cart contents
  const nItems = between(1, 3);
  const items: CartItem[] = [];
  let value = 0;
  const seen = new Set<string>();
  for (let k = 0; k < nItems; k++) {
    let p = pick(CPRODUCTS);
    if (seen.has(p[0])) p = pick(CPRODUCTS);
    seen.add(p[0]);
    const q = rng() < 0.85 ? 1 : 2;
    items.push({ name: p[0], qty: q, amt: p[1] * q });
    value += p[1] * q;
  }

  // time in cart (minutes before abandon/convert)
  const timeMin = status === "converted" ? between(3, 40) : between(8, 2880);
  // exit step (only meaningful when not converted)
  const exitStep = status === "converted" ? "—" : pick(EXIT_STEPS);

  // recovery email journey (only for abandoned/recovered)
  let email: RecoveryEmail;
  if (status === "converted") {
    email = { sent: false };
  } else {
    const sent = rng() < 0.82;
    const opened = sent && rng() < 0.55;
    const clicked = opened && rng() < 0.5;
    email = { sent, opened, clicked };
  }

  // dates — anchored to 26 May 2026
  const daysAgo = between(0, 29);
  const dt = new Date(2026, 4, 26);
  dt.setDate(dt.getDate() - daysAgo);
  dt.setHours(between(8, 22), between(0, 59));

  const source = pick(SOURCES);
  const device: Device = rng() < 0.64 ? "Mobile" : "Desktop";
  const orderId =
    status === "converted" || status === "recovered" ? "#" + (64000 - between(20, 900)) : null;

  // timeline
  const fmt = (d: Date) =>
    d
      .toLocaleString("en-GB", { day: "numeric", month: "short", hour: "2-digit", minute: "2-digit" })
      .replace(",", "");
  const tl: Array<[string, string]> = [];
  let c = new Date(dt);
  tl.push(["Cart started", fmt(c)]);
  c = new Date(c.getTime() + timeMin * 60000);
  if (status === "converted") {
    tl.push(["Checked out", fmt(c)]);
  } else {
    tl.push([`Abandoned at ${exitStep.toLowerCase()}`, fmt(c)]);
    if (email.sent) {
      c = new Date(c.getTime() + 3600000);
      tl.push(["Recovery email sent", fmt(c)]);
    }
    if (email.opened) {
      c = new Date(c.getTime() + 5400000);
      tl.push(["Email opened", fmt(c)]);
    }
    if (status === "recovered") {
      c = new Date(c.getTime() + 7200000);
      tl.push(["Returned & ordered", fmt(c)]);
    }
  }

  return {
    id: "CART-" + (8800 + i),
    date: dt.toISOString().slice(0, 10),
    ts: dt.getTime(),
    time: dt.toLocaleString("en-GB", { hour: "2-digit", minute: "2-digit" }),
    customer: rng() < 0.7 ? `${pick(FIRST)} ${pick(LAST)}` : "Guest",
    items,
    nItems,
    value,
    status,
    timeMin,
    timeLabel: timeMin < 60 ? `${timeMin} min` : `${(timeMin / 60).toFixed(1)} hr`,
    exitStep,
    email,
    source,
    device,
    orderId,
    tl,
  };
}

/* The 50 deterministic cart records, newest first. */
export const CARTS: CartRecord[] = Array.from({ length: 50 }, (_, i) => genCart(i + 1)).sort(
  (a, b) => b.ts - a.ts,
);

