/* ─────────────────────────── Helpers (pure, reused by the page) ─────────────────────────── */

export function statusLabel(s: string): string {
  return s.charAt(0).toUpperCase() + s.slice(1);
}

export function usd(n: number): string {
  return "$" + Math.round(n).toLocaleString();
}

/** Count distinct values for a filterable column, sorted by frequency. */
export function uniqueVals(key: FilterKey): Array<[string, number]> {
  const m: Record<string, number> = {};
  for (const o of CARTS) {
    const v = o[key];
    m[v] = (m[v] || 0) + 1;
  }
  return Object.entries(m).sort((a, b) => b[1] - a[1]);
}

/** 30-day abandoned-per-day buckets ending 26 May 2026 (for the trend sparkline). */
export function abandonedPerDay(rows: CartRecord[]): number[] {
  const end = new Date(2026, 4, 26);
  const buckets: Array<{ iso: string; c: number }> = [];
  for (let i = 29; i >= 0; i--) {
    const d = new Date(end);
    d.setDate(end.getDate() - i);
    buckets.push({ iso: d.toISOString().slice(0, 10), c: 0 });
  }
  const idx: Record<string, number> = {};
  buckets.forEach((b, i) => (idx[b.iso] = i));
  for (const o of rows) {
    if (o.status === "converted") continue;
    if (o.date in idx) buckets[idx[o.date]].c++;
  }
  return buckets.map((b) => b.c);
}
