"use client";

/* ════════════════════════════════════════════════════════════════════════
   DATA › CARTS & ABANDONMENT — record-explorer.
   Port of magellan-data-carts.html. A cart is a neutral record: contents,
   value, and what happened next. Abandoned value is POTENTIAL, never booked;
   the verdict (is abandonment too high? fix the flow?) belongs to a Room.

   Chrome aligned to the convention: canonical <DeptHeader dept="data"> + the
   compass-blue accent (var(--d-data)) used as an ACCENT only. The table is
   genuinely sortable (§8.13), the search filters rows, the filter chips toggle
   values via a checklist popover, rows expand to a detail panel, and a
   calendar/period popover narrows the date range — all lightweight useState.
   Currency is USD ($). Sparkline is hand-built SVG (no chart library).
   ════════════════════════════════════════════════════════════════════════ */

import { useEffect, useLayoutEffect, useMemo, useRef, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import {
  CARTS,
  CARTS_META,
  CAL_PRESETS,
  COLUMNS,
  CROSS_ROOM,
  FILTER_CHIPS,
  KPI_META,
  STATUS_META,
  abandonedPerDay,
  statusLabel,
  uniqueVals,
  usd,
  type CartRecord,
  type ColumnKey,
  type FilterKey,
} from "@/features/data/api/data-carts-data";
import "./carts.css";

/* ───────────────────────── small icons (inline SVG) ───────────────────────── */

const SearchIcon = () => (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
    <circle cx="11" cy="11" r="7" />
    <line x1="21" y1="21" x2="16.5" y2="16.5" />
  </svg>
);

const CalIcon = () => (
  <svg className="cd-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
    <rect x="3" y="4" width="18" height="17" rx="2" />
    <line x1="3" y1="9" x2="21" y2="9" />
    <line x1="8" y1="2" x2="8" y2="6" />
    <line x1="16" y1="2" x2="16" y2="6" />
  </svg>
);

/* ───────────────────────── sort / filter types ───────────────────────── */

type SortKey = "date" | ColumnKey;
type Filters = Record<FilterKey, Set<string>>;
interface Range {
  from: string | null;
  to: string | null;
  preset: string;
}

const TODAY = new Date(2026, 4, 26);
const PAGE_SIZES = [10, 20, 50];
const DOW = ["Su", "Mo", "Tu", "We", "Th", "Fr", "Sa"];

function fmtISO(d: Date) {
  return d.toISOString().slice(0, 10);
}
function rangeFromPreset(p: string): { from: string | null; to: string | null } {
  let from: Date | null = null;
  let to: Date | null = null;
  if (p === "7") {
    from = new Date(TODAY);
    from.setDate(TODAY.getDate() - 6);
    to = TODAY;
  } else if (p === "30") {
    from = new Date(TODAY);
    from.setDate(TODAY.getDate() - 29);
    to = TODAY;
  } else if (p === "tm") {
    from = new Date(2026, 4, 1);
    to = TODAY;
  } else if (p === "lm") {
    from = new Date(2026, 3, 1);
    to = new Date(2026, 3, 30);
  }
  return from && to ? { from: fmtISO(from), to: fmtISO(to) } : { from: null, to: null };
}
function rangeShort(r: Range): string {
  if (!r.from || !r.to) return r.preset === "all" ? "All time" : "—";
  const f = new Date(r.from);
  const t = new Date(r.to);
  const o: Intl.DateTimeFormatOptions = { day: "numeric", month: "short" };
  return r.from === r.to
    ? f.toLocaleDateString("en-GB", o)
    : `${f.toLocaleDateString("en-GB", o)} – ${t.toLocaleDateString("en-GB", o)}`;
}

/* ════════════════════════════════════════════════════════════════════════ */

export default function CartsPage() {
  const [search, setSearch] = useState("");
  const [filters, setFilters] = useState<Filters>({
    status: new Set(),
    exitStep: new Set(),
    device: new Set(),
  });
  const [range, setRange] = useState<Range>({ from: null, to: null, preset: "all" });
  const [sortKey, setSortKey] = useState<SortKey>("date");
  const [sortDir, setSortDir] = useState<-1 | 1>(-1);
  const [open, setOpen] = useState<Set<string>>(new Set());
  const [selected, setSelected] = useState<Set<string>>(new Set());
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(10);
  const [pop, setPop] = useState<null | FilterKey | "date">(null);

  const cols = COLUMNS.filter((c) => c.on);

  // Close any popover on outside click.
  useEffect(() => {
    const onDoc = (e: MouseEvent) => {
      if ((e.target as HTMLElement | null)?.closest?.(".pop, .filter-chip, .btn-util")) return;
      setPop(null);
    };
    document.addEventListener("click", onDoc);
    return () => document.removeEventListener("click", onDoc);
  }, []);
  const stop = (e: React.MouseEvent) => e.stopPropagation();

  /* ── pipeline: search → filter → range → sort ── */
  const filtered = useMemo(() => {
    let rows = CARTS.slice();
    const q = search.trim().toLowerCase();
    if (q) {
      rows = rows.filter(
        (o) =>
          o.id.toLowerCase().includes(q) ||
          o.customer.toLowerCase().includes(q) ||
          o.status.includes(q) ||
          o.exitStep.toLowerCase().includes(q),
      );
    }
    if (filters.status.size) rows = rows.filter((o) => filters.status.has(o.status));
    if (filters.exitStep.size) rows = rows.filter((o) => filters.exitStep.has(o.exitStep));
    if (filters.device.size) rows = rows.filter((o) => filters.device.has(o.device));
    if (range.from && range.to) {
      rows = rows.filter((o) => o.date >= range.from! && o.date <= range.to!);
    }
    rows.sort((a, b) => {
      let x: number | string;
      let y: number | string;
      if (sortKey === "date" || sortKey === "id") {
        x = a.ts;
        y = b.ts;
      } else if (sortKey === "email") {
        x = a.email.sent ? (a.email.clicked ? 3 : a.email.opened ? 2 : 1) : 0;
        y = b.email.sent ? (b.email.clicked ? 3 : b.email.opened ? 2 : 1) : 0;
      } else {
        x = a[sortKey] as number | string;
        y = b[sortKey] as number | string;
      }
      if (typeof x === "string" && typeof y === "string") return sortDir * x.localeCompare(y);
      return sortDir * ((x as number) - (y as number));
    });
    return rows;
  }, [search, filters, range, sortKey, sortDir]);

  /* ── KPIs computed live from the filtered set ── */
  const kpi = useMemo(() => {
    const n = filtered.length;
    const abandoned = filtered.filter((o) => o.status === "abandoned");
    const recovered = filtered.filter((o) => o.status === "recovered");
    const abandonmentRate = n ? ((abandoned.length + recovered.length) / n) * 100 : 0;
    const recoverable = abandoned.reduce((s, o) => s + o.value, 0);
    const eligible = recovered.length + abandoned.filter((o) => o.email.sent).length;
    const recoveryRate = eligible ? (recovered.length / eligible) * 100 : 0;
    const avgValue = n ? filtered.reduce((s, o) => s + o.value, 0) / n : 0;
    return { n, abandonmentRate, recoverable, recoveryRate, avgValue };
  }, [filtered]);

  /* ── pagination math ── */
  const total = filtered.length;
  const pages = Math.max(1, Math.ceil(total / pageSize));
  const safePage = Math.min(page, pages);
  const start = (safePage - 1) * pageSize;
  const pageRows = filtered.slice(start, start + pageSize);

  /* ── header sort handler ── */
  const onSort = (k: SortKey) => {
    if (sortKey === k) {
      setSortDir((d) => (d === 1 ? -1 : 1));
    } else {
      setSortKey(k);
      setSortDir(["customer", "status", "source", "device", "exitStep"].includes(k) ? 1 : -1);
    }
  };

  const toggleRow = (id: string) =>
    setOpen((cur) => {
      const next = new Set(cur);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  const toggleSel = (id: string) =>
    setSelected((cur) => {
      const next = new Set(cur);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });

  const pageAllSelected = pageRows.length > 0 && pageRows.every((o) => selected.has(o.id));
  const toggleAllOnPage = () =>
    setSelected((cur) => {
      const next = new Set(cur);
      if (pageAllSelected) pageRows.forEach((o) => next.delete(o.id));
      else pageRows.forEach((o) => next.add(o.id));
      return next;
    });

  const resetAll = () => {
    setSearch("");
    setFilters({ status: new Set(), exitStep: new Set(), device: new Set() });
    setRange({ from: null, to: null, preset: "all" });
    setPage(1);
  };

  const anyFilter =
    !!search.trim() ||
    filters.status.size > 0 ||
    filters.exitStep.size > 0 ||
    filters.device.size > 0 ||
    range.preset !== "all";

  /* ── pager window (1 … cur-1 cur cur+1 … last) ── */
  const pagerWin: Array<number | "…"> = [];
  for (let p = 1; p <= pages; p++) {
    if (p === 1 || p === pages || (p >= safePage - 1 && p <= safePage + 1)) pagerWin.push(p);
    else if (pagerWin[pagerWin.length - 1] !== "…") pagerWin.push("…");
  }

  return (
    <div className="data-carts">
      <div className="dept-wrap">
        {/* ── HEADER ── */}
        <DeptHeader
          dept="data"
          title="Carts & Abandonment"
          meta={
            <>
              <span className="live">Live</span> · {CARTS_META}
            </>
          }
          actions={
            <>
              <button className="btn-util">Export ↓</button>
              <button className="btn-util">Columns</button>
              <button className="btn-util primary">+ Saved view</button>
            </>
          }
        />

        <div className="head-pad" />

        {/* ── TOOLS ROW: search + filter chips + date control ── */}
        <div className="filter-row" onClick={stop}>
          <div className="pt-search">
            <SearchIcon />
            <input
              type="text"
              value={search}
              onChange={(e) => {
                setSearch(e.target.value);
                setPage(1);
              }}
              placeholder="Search carts by ID, customer, status, exit step…"
            />
          </div>

          {FILTER_CHIPS.map(({ key, label }) => {
            const set = filters[key];
            return (
              <div key={key} style={{ position: "relative" }}>
                <button
                  className={`filter-chip${set.size ? " active" : ""}`}
                  onClick={(e) => {
                    e.stopPropagation();
                    setPop((p) => (p === key ? null : key));
                  }}
                >
                  {set.size ? (
                    <>
                      {label} · {set.size}{" "}
                      <span
                        className="x"
                        onClick={(e) => {
                          e.stopPropagation();
                          setFilters((cur) => ({ ...cur, [key]: new Set<string>() }));
                          setPage(1);
                        }}
                      >
                        ×
                      </span>
                    </>
                  ) : (
                    <>
                      {label} <span className="caret">▾</span>
                    </>
                  )}
                </button>
                {pop === key && (
                  <FilterPopover
                    fkey={key}
                    selected={set}
                    onToggle={(v) => {
                      setFilters((cur) => {
                        const next = new Set(cur[key]);
                        if (next.has(v)) next.delete(v);
                        else next.add(v);
                        return { ...cur, [key]: next };
                      });
                      setPage(1);
                    }}
                    onClear={() => {
                      setFilters((cur) => ({ ...cur, [key]: new Set<string>() }));
                      setPage(1);
                      setPop(null);
                    }}
                    onApply={() => setPop(null)}
                  />
                )}
              </div>
            );
          })}

          {/* date / period control */}
          <div style={{ position: "relative" }}>
            <button
              className={`filter-chip date-chip${range.preset !== "all" ? " active" : ""}`}
              onClick={(e) => {
                e.stopPropagation();
                setPop((p) => (p === "date" ? null : "date"));
              }}
            >
              <CalIcon />
              {range.preset !== "all" ? rangeShort(range) : "All time"}{" "}
              <span className="caret">▾</span>
            </button>
            {pop === "date" && (
              <CalendarPopover
                range={range}
                onApply={(r) => {
                  setRange(r);
                  setPage(1);
                  setPop(null);
                }}
                onClear={() => {
                  setRange({ from: null, to: null, preset: "all" });
                  setPage(1);
                  setPop(null);
                }}
              />
            )}
          </div>

          <button className="filter-clear" onClick={resetAll}>
            Clear all
          </button>
        </div>

        {/* ── KPI STRIP (computed live) ── */}
        <div className="kpi-strip">
          {KPI_META.map((m) => {
            let value: React.ReactNode;
            let sub: string;
            if (m.key === "abandonment") {
              value = `${kpi.abandonmentRate.toFixed(1)}%`;
              sub = `${kpi.n} carts · current view`;
            } else if (m.key === "recoverable") {
              value = (
                <>
                  <span className="cur">$</span>
                  {Math.round(kpi.recoverable).toLocaleString()}
                </>
              );
              sub = "potential · not booked";
            } else if (m.key === "recovery") {
              value = `${kpi.recoveryRate.toFixed(1)}%`;
              sub = "of emailed carts";
            } else {
              value = (
                <>
                  <span className="cur">$</span>
                  {Math.round(kpi.avgValue).toLocaleString()}
                </>
              );
              sub = "avg cart value";
            }
            return (
              <div key={m.key} className="kpi-card" style={{ "--accent": m.accent } as React.CSSProperties}>
                <div className="kpi-label">{m.label}</div>
                <div className="kpi-value">{value}</div>
                <div className="kpi-sub">{sub}</div>
                <div className={`kpi-prov ${m.prov.kind}`}>
                  <span className="pdot" />
                  {m.prov.text}
                </div>
              </div>
            );
          })}
        </div>

        {/* ── COMPACT TREND ── */}
        <div className="trend-card">
          <div className="trend-head">
            <div className="trend-kicker">Abandoned carts per day · last 30 days</div>
            <div className="trend-note">reflects current filters · hover any day</div>
          </div>
          <TrendChart rows={filtered} />
        </div>

        {/* ── BULK BAR (only when rows are selected) ── */}
        {selected.size > 0 && (
          <div className="bulkbar">
            <span className="bb-count">
              {selected.size} cart{selected.size > 1 ? "s" : ""} selected
            </span>
            <button className="bb-btn">Export selected ↓</button>
            <button className="bb-clear" onClick={() => setSelected(new Set())}>
              Clear selection
            </button>
          </div>
        )}

        {/* ── RECORDS HEADER ── */}
        <div className="records-head">
          <span className="records-title">Cart records</span>
          <span className="records-count">
            {total
              ? `Showing ${start + 1}–${Math.min(start + pageSize, total)} of ${total}`
              : "No matching records"}
          </span>
        </div>

        {/* ── TABLE ── */}
        <div className="table-wrap">
          <div className="table-scroll">
            <table className="otable">
              <thead>
                <tr>
                  <th className="plain" style={{ width: 30 }} />
                  <th className="plain" style={{ width: 34 }}>
                    <span
                      className={`row-check${pageAllSelected ? " on" : ""}`}
                      onClick={(e) => {
                        e.stopPropagation();
                        toggleAllOnPage();
                      }}
                    />
                  </th>
                  {cols.map((c) => {
                    const sk: SortKey = c.k === "id" ? "date" : c.k;
                    const active = sortKey === sk;
                    return (
                      <th
                        key={c.k}
                        className={`${c.num ? "num" : ""}${active ? " sorted" : ""}`}
                        onClick={() => onSort(sk)}
                      >
                        {c.label}
                        <span className="sortcaret">{active && sortDir === 1 ? "▴" : "▾"}</span>
                      </th>
                    );
                  })}
                </tr>
              </thead>
              <tbody>
                {total === 0 ? (
                  <tr>
                    <td colSpan={cols.length + 2}>
                      <div className="empty-state">
                        <div className="es-icon">
                          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                            <circle cx="11" cy="11" r="7" />
                            <line x1="21" y1="21" x2="16.5" y2="16.5" />
                          </svg>
                        </div>
                        <div className="es-title">No carts match this view</div>
                        <div className="es-sub">Try widening the date range or clearing a filter.</div>
                        <button className="es-btn" onClick={resetAll}>
                          Clear all filters
                        </button>
                      </div>
                    </td>
                  </tr>
                ) : (
                  pageRows.map((o) => {
                    const isOpen = open.has(o.id);
                    const isSel = selected.has(o.id);
                    return (
                      <Row
                        key={o.id}
                        o={o}
                        cols={cols}
                        isOpen={isOpen}
                        isSel={isSel}
                        onToggleRow={() => toggleRow(o.id)}
                        onToggleSel={() => toggleSel(o.id)}
                      />
                    );
                  })
                )}
              </tbody>
            </table>
          </div>

          {/* ── PAGER ── */}
          {total > 0 && (
            <div className="pager">
              <div className="pager-size">
                Rows{" "}
                <select
                  value={pageSize}
                  onChange={(e) => {
                    setPageSize(Number(e.target.value));
                    setPage(1);
                  }}
                >
                  {PAGE_SIZES.map((n) => (
                    <option key={n} value={n}>
                      {n}
                    </option>
                  ))}
                </select>
              </div>
              <div className="pager-ctrl">
                <button
                  className="pager-btn"
                  disabled={safePage === 1}
                  onClick={() => setPage(safePage - 1)}
                >
                  ‹
                </button>
                {pagerWin.map((p, i) =>
                  p === "…" ? (
                    <span key={`e${i}`} className="pager-ellipsis">
                      …
                    </span>
                  ) : (
                    <button
                      key={p}
                      className={`pager-btn${p === safePage ? " on" : ""}`}
                      onClick={() => setPage(p)}
                    >
                      {p}
                    </button>
                  ),
                )}
                <button
                  className="pager-btn"
                  disabled={safePage === pages}
                  onClick={() => setPage(safePage + 1)}
                >
                  ›
                </button>
              </div>
            </div>
          )}
        </div>

        {/* ── CROSS-ROOM FOOTER ── */}
        <div className="crossroom">
          <span className="cr-label">This record feeds</span>
          {CROSS_ROOM.map((c, i) => (
            <div key={c.room} style={{ display: "contents" }}>
              <div className="cr-item">
                <span className="cr-dot" style={{ background: c.dot }} />
                <strong>{c.room}</strong> — {c.note}
              </div>
              {i < CROSS_ROOM.length - 1 && <div className="cr-sep" />}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

/* ───────────────────────── Row + cells ───────────────────────── */

function Cell({ o, k }: { o: CartRecord; k: ColumnKey }) {
  switch (k) {
    case "id":
      return (
        <>
          <div className="oid">{o.id}</div>
          <div className="odate">
            {o.date} · {o.time}
          </div>
        </>
      );
    case "customer":
      return <span className="ocustomer">{o.customer}</span>;
    case "status": {
      const [label, bg, color] = STATUS_META[o.status];
      return (
        <span className="pill" style={{ background: bg, color }}>
          {label}
        </span>
      );
    }
    case "value":
      return <>{usd(o.value)}</>;
    case "exitStep":
      return o.exitStep === "—" ? (
        <span className="muted">—</span>
      ) : (
        <span className="cat-tag">{o.exitStep}</span>
      );
    case "email":
      return <EmailDots o={o} />;
    case "timeMin":
      return <span>{o.timeLabel}</span>;
    case "device":
      return <span className="pay">{o.device}</span>;
    case "source":
      return <span className="src">{o.source}</span>;
  }
}

function EmailDots({ o }: { o: CartRecord }) {
  if (!o.email.sent) return <span className="not-sent">not sent</span>;
  const states: Array<[string, boolean]> = [
    ["sent", true],
    ["opened", !!o.email.opened],
    ["clicked", !!o.email.clicked],
  ];
  const label = o.email.clicked ? "clicked" : o.email.opened ? "opened" : "sent";
  return (
    <span className="em-journey">
      {states.map(([lbl, on]) => (
        <span key={lbl} className={`em-dot${on ? " on" : ""}`} title={lbl} />
      ))}
      <span className="em-label">{label}</span>
    </span>
  );
}

function cartRoute(o: CartRecord): string {
  if (o.status === "converted")
    return `This cart converted${o.orderId ? " into " + o.orderId : ""}. Recorded for the funnel — no action needed.`;
  if (o.status === "recovered")
    return `Recovered after a recovery email${o.orderId ? " → " + o.orderId : ""}. The flow that won it back lives in Growth.`;
  return `Still abandoned at ${o.exitStep.toLowerCase()}, ${usd(o.value)} in potential value. If this exit step is a pattern, the fix is checkout friction (Operations) or the recovery flow (Growth).`;
}
function cartRouteRoom(o: CartRecord): string {
  if (["Payment", "Address entry", "Delivery date"].includes(o.exitStep)) return "Operations";
  return "Growth";
}

function Row({
  o,
  cols,
  isOpen,
  isSel,
  onToggleRow,
  onToggleSel,
}: {
  o: CartRecord;
  cols: typeof COLUMNS;
  isOpen: boolean;
  isSel: boolean;
  onToggleRow: () => void;
  onToggleSel: () => void;
}) {
  const totalLabel = o.status === "abandoned" ? "Potential value" : "Cart value";
  const emailLabel = o.email.sent
    ? o.email.clicked
      ? "Sent · opened · clicked"
      : o.email.opened
        ? "Sent · opened"
        : "Sent"
    : "Not sent";
  return (
    <>
      <tr className={`orow${isOpen ? " open" : ""}${isSel ? " selected" : ""}`} onClick={onToggleRow}>
        <td>
          <span className="exp-caret">▶</span>
        </td>
        <td>
          <span
            className={`row-check${isSel ? " on" : ""}`}
            onClick={(e) => {
              e.stopPropagation();
              onToggleSel();
            }}
          />
        </td>
        {cols.map((c) => (
          <td key={c.k} className={c.num ? "num-cell" : ""}>
            <Cell o={o} k={c.k} />
          </td>
        ))}
      </tr>
      {isOpen && (
        <tr className="detail-row">
          <td colSpan={cols.length + 2}>
            <div className="detail-inner">
              <div className="detail-pad">
                <div className="detail-top">
                  {/* Cart contents */}
                  <div>
                    <div className="detail-block-label">Cart contents</div>
                    {o.items.map((it, i) => (
                      <div key={i} className="lineitem">
                        <div>
                          <span className="li-name">{it.name}</span>
                          <span className="li-qty">×{it.qty}</span>
                        </div>
                        <div className="li-amt">{usd(it.amt)}</div>
                      </div>
                    ))}
                    <div className="li-total">
                      <span className="lt-k">{totalLabel}</span>
                      <span className="lt-v">{usd(o.value)}</span>
                    </div>
                  </div>

                  {/* Cart details */}
                  <div>
                    <div className="detail-block-label">Cart details</div>
                    <div className="kv">
                      <span className="k">Status</span>
                      <span className="v">{statusLabel(o.status)}</span>
                    </div>
                    <div className="kv">
                      <span className="k">Time in cart</span>
                      <span className="v mono">{o.timeLabel}</span>
                    </div>
                    <div className="kv">
                      <span className="k">Exit step</span>
                      <span className="v">{o.exitStep}</span>
                    </div>
                    <div className="kv">
                      <span className="k">Device · source</span>
                      <span className="v mono">
                        {o.device} · {o.source}
                      </span>
                    </div>
                    <div className="kv">
                      <span className="k">Became order</span>
                      <span className="v mono">
                        {o.orderId ? (
                          <a className="order-link" onClick={(e) => e.preventDefault()} href="#">
                            {o.orderId}
                          </a>
                        ) : (
                          <span className="muted">—</span>
                        )}
                      </span>
                    </div>
                  </div>

                  {/* What happened — and where to act */}
                  <div>
                    <div className="detail-block-label">What happened — and where to act</div>
                    <div className="archetype">
                      <div className="arch-label">{statusLabel(o.status)} cart</div>
                      <div className="arch-text">{cartRoute(o)}</div>
                      <div className="arch-route">
                        {o.status === "converted" ? (
                          "Recorded for the funnel"
                        ) : (
                          <>
                            Act on this in the <strong>{cartRouteRoom(o)} room →</strong>
                          </>
                        )}
                      </div>
                    </div>
                  </div>
                </div>

                <div className="detail-second">
                  {/* Cart journey */}
                  <div>
                    <div className="detail-block-label">Cart journey</div>
                    <div className="timeline">
                      {o.tl.map((t, idx) => {
                        const last =
                          idx === o.tl.length - 1 &&
                          (o.status === "converted" || o.status === "recovered");
                        return (
                          <div key={idx} className={`tl-step${last ? " last" : ""}`}>
                            <div className="tl-name">{t[0]}</div>
                            <div className="tl-time">{t[1]}</div>
                          </div>
                        );
                      })}
                    </div>
                  </div>

                  {/* Record */}
                  <div>
                    <div className="detail-block-label">Record</div>
                    <div className="kv">
                      <span className="k">Cart ID</span>
                      <span className="v mono">{o.id}</span>
                    </div>
                    <div className="kv">
                      <span className="k">Items</span>
                      <span className="v mono">{o.nItems}</span>
                    </div>
                    <div className="kv">
                      <span className="k">{o.status === "abandoned" ? "Potential value" : "Cart value"}</span>
                      <span className="v mono">{usd(o.value)}</span>
                    </div>
                    <div className="kv">
                      <span className="k">Recovery email</span>
                      <span className="v">{emailLabel}</span>
                    </div>
                    <div className="kv">
                      <span className="k">Became order</span>
                      <span className="v mono">{o.orderId || "—"}</span>
                    </div>
                  </div>
                </div>

                <div className="detail-note">
                  This is a <strong>record</strong> — what was in the cart and what happened.
                  Abandoned value is <em>potential</em>, never booked revenue. Whether abandonment is
                  too high, and the recovery flow itself, are verdicts for the <strong>Growth</strong>{" "}
                  room; checkout friction is <strong>Operations</strong>.
                </div>
              </div>
            </div>
          </td>
        </tr>
      )}
    </>
  );
}

/* ───────────────────────── Filter checklist popover ───────────────────────── */

function FilterPopover({
  fkey,
  selected,
  onToggle,
  onClear,
  onApply,
}: {
  fkey: FilterKey;
  selected: Set<string>;
  onToggle: (v: string) => void;
  onClear: () => void;
  onApply: () => void;
}) {
  const vals = useMemo(() => uniqueVals(fkey), [fkey]);
  const lab = (v: string) => (fkey === "status" ? statusLabel(v) : v);
  return (
    <div
      className="pop"
      onClick={(e) => e.stopPropagation()}
      style={{ top: "calc(100% + 8px)", left: 0 }}
    >
      <div className="pop-head">Filter by {fkey}</div>
      <div className="pop-body">
        {vals.map(([v, c]) => (
          <div
            key={v}
            className={`check-item${selected.has(v) ? " on" : ""}`}
            onClick={() => onToggle(v)}
          >
            <span className="check-box" />
            {lab(v)}
            <span className="check-count">{c}</span>
          </div>
        ))}
      </div>
      <div className="pop-foot">
        <button className="pop-btn" onClick={onClear}>
          Clear
        </button>
        <button className="pop-btn primary" onClick={onApply}>
          Apply
        </button>
      </div>
    </div>
  );
}

/* ───────────────────────── Calendar / period popover ───────────────────────── */

function CalendarPopover({
  range,
  onApply,
  onClear,
}: {
  range: Range;
  onApply: (r: Range) => void;
  onClear: () => void;
}) {
  const [view, setView] = useState(new Date(2026, 4, 1));
  const [draft, setDraft] = useState<Range>(range);
  const [pick, setPick] = useState<string[]>(range.from && range.to ? [range.from, range.to] : []);

  const y = view.getFullYear();
  const m = view.getMonth();
  const title = view.toLocaleDateString("en-GB", { month: "long", year: "numeric" });
  const first = new Date(y, m, 1).getDay();
  const days = new Date(y, m + 1, 0).getDate();
  const prevDays = new Date(y, m, 0).getDate();

  const choosePreset = (p: string) => {
    if (p === "custom") {
      setDraft((d) => ({ ...d, preset: "custom" }));
      return;
    }
    const r = rangeFromPreset(p);
    setDraft({ from: r.from, to: r.to, preset: p });
    setPick(r.from && r.to ? [r.from, r.to] : []);
  };

  const chooseDay = (iso: string) => {
    setDraft((d) => ({ ...d, preset: "custom" }));
    if (pick.length === 0 || pick.length === 2) {
      setPick([iso]);
      setDraft((d) => ({ ...d, from: iso, to: iso, preset: "custom" }));
    } else {
      const next = [...pick, iso].sort();
      setPick(next);
      setDraft((d) => ({ ...d, from: next[0], to: next[1], preset: "custom" }));
    }
  };

  const cells: React.ReactNode[] = [];
  for (let i = first - 1; i >= 0; i--) {
    cells.push(
      <div key={`p${i}`} className="cal-day muted">
        {prevDays - i}
      </div>,
    );
  }
  for (let d = 1; d <= days; d++) {
    const iso = fmtISO(new Date(y, m, d));
    let cls = "";
    const { from, to } = draft;
    if (from && to) {
      if (iso === from && iso === to) cls = "range-single";
      else if (iso === from) cls = "range-start";
      else if (iso === to) cls = "range-end";
      else if (iso > from && iso < to) cls = "in-range";
    } else if (pick.length === 1 && pick[0] === iso) {
      cls = "range-single";
    }
    cells.push(
      <button
        key={iso}
        className={`cal-day ${cls}`}
        onClick={(e) => {
          e.stopPropagation();
          chooseDay(iso);
        }}
      >
        {d}
      </button>,
    );
  }

  return (
    <div
      className="pop"
      onClick={(e) => e.stopPropagation()}
      style={{ top: "calc(100% + 8px)", right: 0 }}
    >
      <div className="cal">
        <div className="cal-presets">
          {CAL_PRESETS.map(([k, l]) => (
            <button
              key={k}
              className={`cal-preset${draft.preset === k ? " on" : ""}`}
              onClick={(e) => {
                e.stopPropagation();
                choosePreset(k);
              }}
            >
              {l}
            </button>
          ))}
        </div>
        <div className="cal-month-head">
          <button
            className="cal-nav"
            onClick={(e) => {
              e.stopPropagation();
              setView(new Date(y, m - 1, 1));
            }}
          >
            ‹
          </button>
          <div className="cal-month-title">{title}</div>
          <button
            className="cal-nav"
            onClick={(e) => {
              e.stopPropagation();
              setView(new Date(y, m + 1, 1));
            }}
          >
            ›
          </button>
        </div>
        <div className="cal-grid">
          {DOW.map((d) => (
            <div key={d} className="cal-dow">
              {d}
            </div>
          ))}
          {cells}
        </div>
        <div className="pop-foot">
          <button className="pop-btn" onClick={onClear}>
            Clear
          </button>
          <button
            className="pop-btn primary"
            onClick={() =>
              onApply(
                draft.from && draft.to
                  ? draft
                  : { from: null, to: null, preset: "all" },
              )
            }
          >
            Apply
          </button>
        </div>
      </div>
    </div>
  );
}

/* ───────────────────────── Trend sparkline (hand-built SVG) ───────────────────────── */

const T_H = 170;
const TPAD = { l: 38, r: 14, t: 14, b: 24 };

function TrendChart({ rows }: { rows: CartRecord[] }) {
  const svgRef = useRef<SVGSVGElement | null>(null);
  const tipRef = useRef<HTMLDivElement | null>(null);
  const [vbw, setVbw] = useState(900);

  const cur = useMemo(() => abandonedPerDay(rows), [rows]);
  const tmax = useMemo(() => Math.max(6, Math.ceil(Math.max(...cur, 0) / 2) * 2), [cur]);

  useLayoutEffect(() => {
    const el = svgRef.current;
    if (!el) return;
    const measure = () =>
      setVbw(Math.max(560, Math.round(el.getBoundingClientRect().width || 900)));
    measure();
    const ro = new ResizeObserver(measure);
    ro.observe(el);
    return () => ro.disconnect();
  }, []);

  const n = cur.length;
  const inner = vbw - TPAD.l - TPAD.r;
  const tX = (i: number) => TPAD.l + (inner * i) / (n - 1);
  const top = TPAD.t + 4;
  const bot = T_H - TPAD.b;
  const tY = (v: number) => top + ((tmax - v) / (tmax - 0)) * (bot - top);

  const xs = cur.map((_, i) => tX(i));
  const cys = cur.map((v) => tY(v));

  const reduceMotion =
    typeof window !== "undefined" &&
    window.matchMedia?.("(prefers-reduced-motion: reduce)").matches;

  const buildInner = () => {
    let s = "";
    for (const g of [0, tmax / 2, tmax]) {
      const gy = tY(g);
      s += `<line x1="${TPAD.l}" y1="${gy.toFixed(1)}" x2="${vbw - TPAD.r}" y2="${gy.toFixed(1)}" stroke="rgba(0,0,0,${g === 0 ? 0.1 : 0.05})" stroke-width="0.5"/>`;
      s += `<text x="${TPAD.l - 8}" y="${(gy + 3).toFixed(1)}" text-anchor="end" font-family="JetBrains Mono" font-size="10" fill="#8a8d94">${g}</text>`;
    }
    const cp = cur.map((v, i) => `${i ? "L" : "M"} ${xs[i].toFixed(1)} ${tY(v).toFixed(1)}`).join(" ");
    s += `<path d="${cp} L ${xs[n - 1].toFixed(1)} ${bot} L ${xs[0].toFixed(1)} ${bot} Z" fill="rgba(91,124,176,0.13)"/>`;
    s += `<path class="t-line" d="${cp}" stroke="#2a4070" stroke-width="2.5" fill="none" stroke-linecap="round" stroke-linejoin="round"/>`;
    for (let i = 0; i < n; i++) {
      if (i % 3 === 0 && i !== n - 1) {
        s += `<rect x="${(xs[i] - 2).toFixed(1)}" y="${(tY(cur[i]) - 2).toFixed(1)}" width="4" height="4" rx="0.5" fill="#9aabc4"/>`;
      }
    }
    const ex = xs[n - 1];
    const ey = tY(cur[n - 1]);
    s += `<rect x="${(ex - 7).toFixed(1)}" y="${(ey - 7).toFixed(1)}" width="14" height="14" rx="3" fill="rgba(91,124,176,0.18)"/>`;
    s += `<rect x="${(ex - 3.5).toFixed(1)}" y="${(ey - 3.5).toFixed(1)}" width="7" height="7" rx="1" fill="#2a4070"/>`;
    const valY = ey < TPAD.t + 40 ? ey + 18 : ey - 12;
    s += `<text x="${(ex - 12).toFixed(1)}" y="${valY.toFixed(1)}" text-anchor="end" font-family="Inter" font-size="15" font-weight="300" fill="#2a4070" font-variant-numeric="tabular-nums">${cur[n - 1]} today</text>`;
    s += `<text x="${xs[0].toFixed(1)}" y="${T_H - 8}" text-anchor="start" font-family="JetBrains Mono" font-size="10" fill="#8a8d94">30d ago</text>`;
    s += `<text x="${xs[n - 1].toFixed(1)}" y="${T_H - 8}" text-anchor="end" font-family="JetBrains Mono" font-size="10" fill="#8a8d94">today</text>`;
    s += `<g class="t-hover" style="pointer-events:none;opacity:0;transition:opacity .12s"><line class="t-cross" y1="${TPAD.t}" y2="${bot}" stroke="#3a5285" stroke-width="1" stroke-dasharray="3 3"/><rect class="t-hnode" width="11" height="11" rx="2" fill="#2a4070" stroke="#fff" stroke-width="2"/></g>`;
    for (let i = 0; i < n; i++) {
      const left = i === 0 ? TPAD.l : (xs[i - 1] + xs[i]) / 2;
      const right = i === n - 1 ? vbw - TPAD.r : (xs[i] + xs[i + 1]) / 2;
      s += `<rect class="t-hit" data-i="${i}" x="${left.toFixed(1)}" y="${TPAD.t}" width="${(right - left).toFixed(1)}" height="${(bot - TPAD.t).toFixed(1)}" fill="transparent" style="cursor:crosshair"/>`;
    }
    return s;
  };

  useEffect(() => {
    const svg = svgRef.current;
    if (!svg) return;
    svg.innerHTML = buildInner();

    if (!reduceMotion) {
      const ln = svg.querySelector<SVGPathElement>(".t-line");
      if (ln && ln.getTotalLength) {
        const L = ln.getTotalLength();
        if (L) {
          ln.style.transition = "none";
          ln.style.strokeDasharray = String(L);
          ln.style.strokeDashoffset = String(L);
          ln.getBoundingClientRect();
          ln.style.transition = "stroke-dashoffset 0.7s cubic-bezier(0.22,0.61,0.36,1)";
          ln.style.strokeDashoffset = "0";
        }
      }
    }

    const layer = svg.querySelector<SVGGElement>(".t-hover");
    const cross = svg.querySelector<SVGLineElement>(".t-cross");
    const node = svg.querySelector<SVGRectElement>(".t-hnode");
    const tip = tipRef.current;
    if (!layer || !cross || !node || !tip) return;

    const show = (i: number) => {
      const x = xs[i];
      layer.style.opacity = "1";
      cross.setAttribute("x1", String(x));
      cross.setAttribute("x2", String(x));
      node.setAttribute("x", String(x - 5.5));
      node.setAttribute("y", String(cys[i] - 5.5));
      const d = new Date(TODAY);
      d.setDate(TODAY.getDate() - (29 - i));
      const ds = d.toLocaleDateString("en-GB", { day: "numeric", month: "short" });
      tip.innerHTML = `<div class="tip-month">${ds}</div><div class="tip-row"><span class="tip-dot c"></span>Abandoned<b>${cur[i]}</b></div>`;
      tip.style.opacity = "1";
      const wrap = svg.getBoundingClientRect();
      const px = wrap.left + (x / vbw) * wrap.width;
      const py = wrap.top + (cys[i] / T_H) * wrap.height;
      const tw = tip.offsetWidth || 120;
      let lx = px - tw / 2;
      lx = Math.max(8, Math.min(lx, window.innerWidth - tw - 8));
      tip.style.left = lx + "px";
      tip.style.top = py - tip.offsetHeight - 14 + "px";
    };
    const hide = () => {
      layer.style.opacity = "0";
      tip.style.opacity = "0";
    };

    const hits = svg.querySelectorAll<SVGRectElement>(".t-hit");
    const offs: Array<() => void> = [];
    hits.forEach((r) => {
      const i = Number(r.dataset.i);
      const fn = () => show(i);
      r.addEventListener("mousemove", fn);
      r.addEventListener("mouseenter", fn);
      offs.push(() => {
        r.removeEventListener("mousemove", fn);
        r.removeEventListener("mouseenter", fn);
      });
    });
    svg.addEventListener("mouseleave", hide);
    return () => {
      offs.forEach((off) => off());
      svg.removeEventListener("mouseleave", hide);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [cur, tmax, vbw, reduceMotion]);

  return (
    <div className="trend-chart">
      <div className="chart-tip" ref={tipRef} />
      <svg
        ref={svgRef}
        width="100%"
        viewBox={`0 0 ${vbw} ${T_H}`}
        role="img"
        aria-label="Abandoned carts per day, last 30 days"
      />
    </div>
  );
}
